/** Public URL of a system's bundled default logo, or null if none is shipped. */
export function defaultLogoUrl(slug: string): string | null {
  return SYSTEM_DEFAULT_LOGOS[slug] ? `/system-defaults/logo/${slug}.webp` : null;
}
